func NewRangeQueryRequest[ParamArgsType AllParamConstraint](
	logContext *log.Context,
	termFilters []map[string]any,
	rangeFilters []map[string]*RangeFieldOperators,
	size int,
	sourceProperties []string,
	missingProperties []string,
) *QueryRequest[ParamArgsType] {
	queryRequest := &QueryRequest[ParamArgsType]{}
	queryRequest.withQuery().LogContext = logContext
	queryRequest.
		WithSize(size).
		WithSource(sourceProperties)

	queryRequest.withBool()

	for _, termFilter := range termFilters {
		queryRequest.WithFilter(termFilter)
	}

	shouldQueries := make([]*ShouldQuery, 0)
	if len(rangeFilters) > 0 {
		rangeQuery := &ShouldQuery{
			BoolQueries: &BoolQuery{
				Filters: make([]*Filter, 0, len(rangeFilters)),
			},
		}

		for _, rangeFilter := range rangeFilters {
			rangeQuery.BoolQueries.Filters = append(
				rangeQuery.BoolQueries.Filters,
				&Filter{Range: rangeFilter},
			)
		}
		shouldQueries = append(shouldQueries, rangeQuery)
	}

	if len(missingProperties) > 0 {
		for _, property := range missingProperties {
			shouldQueries = append(shouldQueries, &ShouldQuery{
				BoolQueries: &BoolQuery{
					MustNot: []*mustNot{
						{Exists: &exists{Field: &property}},
					},
				},
			})
		}
	}

	if len(shouldQueries) > 0 {
		queryRequest.Query.BoolQuery.Should = shouldQueries
		minShouldMatch := 1
		queryRequest.Query.BoolQuery.MinimumShouldMatch = &minShouldMatch
	}

	return queryRequest
}

// NewMissingOrDefaultPropertiesQueryRequest creates a QueryRequest to find
// documents where specified properties are either missing or have default
// values.
func NewMissingOrDefaultPropertiesQueryRequest[ParamArgsType AllParamConstraint](
	logContext *log.Context,
	tenantUuid *string,
	properties []string,
	defaultValues map[string]any,
) *QueryRequest[ParamArgsType] {
	queryRequest := &QueryRequest[ParamArgsType]{}

	queryRequest.
		withQuery().
		withBool()

	queryRequest.LogContext = logContext

	// Setup Filters
	if tenantUuid != nil {
		_ = queryRequest.WithFilter(map[string]any{tenantUuidString: tenantUuid})
	}

	// Add properties and default values filters
	if len(properties) > 0 {
		queryRequest.WithMissingOrDefaultProperties(properties, defaultValues)
	}

	return queryRequest
}

// WithMissingOrDefaultProperties adds filters to the QueryRequest to find
// documents where specified properties are either missing or have default
// values.
func (queryRequest *QueryRequest[ParamArgsType]) WithMissingOrDefaultProperties(
	properties []string,
	defaultValues map[string]any,
) *QueryRequest[ParamArgsType] {
	queryRequest.withBool()

	for _, property := range properties {
		queryRequest.Query.BoolQuery.Should = append(
			queryRequest.Query.BoolQuery.Should,
			&ShouldQuery{
				BoolQueries: &BoolQuery{
					MustNot: []*mustNot{
						{Exists: &exists{Field: &property}},
					},
				},
			},
		)

		// Add should clause for property default value if provided
		if defaultValue, ok := defaultValues[property]; ok {
			queryRequest.Query.BoolQuery.Should = append(
				queryRequest.Query.BoolQuery.Should,
				&ShouldQuery{
					BoolQueries: &BoolQuery{
						Filters: []*Filter{
							{Term: map[string]any{property: defaultValue}},
						},
					},
				},
			)
		}
	}

	minShouldMatch := 1
	queryRequest.Query.BoolQuery.MinimumShouldMatch = &minShouldMatch

	return queryRequest
}

// withFilters adds multiple Filters to the given QueryRequest.
func withFilters[ParamArgsType AllParamConstraint](
	queryRequest *QueryRequest[ParamArgsType],
	filterAssociations []*FilterAssociation[ParamArgsType],
	bulkOperationItems *[]*BulkOperationItem[ParamArgsType],
	script *string,
	scriptId *string,
) error {
	queryRequest.
		withBool()

	for _, currentFilterAssociation := range filterAssociations {
		if currentFilterAssociation == nil {
			continue
		} else if !currentFilterAssociation.ArgType.Contains(CascadedDeleteArgType) &&
			!currentFilterAssociation.ArgType.Contains(SearchArgType) &&
			len(currentFilterAssociation.ParamArgs()) == 0 {
			const (
				msg           = "Filter Association has no parameters."
				filterListKey = "filter_list"
				argTypeKey    = "arg_type"
				stateKey      = "state"
			)

			log.Warnw(
				currentFilterAssociation.LogContext,
				msg,
				filterListKey, currentFilterAssociation.Filters,
				argTypeKey, currentFilterAssociation.ArgType,
				stateKey, currentFilterAssociation.state,
			)
			continue
		}

		currentFilterLength := len(queryRequest.Query.BoolQuery.Filters)
		currentFilterCap := cap(queryRequest.Query.BoolQuery.Filters) - currentFilterLength
		currentKeyValueLength := len(currentFilterAssociation.Filters)
		if currentFilterCap-currentKeyValueLength < 0 {
			newSlice := make([]*Filter, currentFilterLength, currentFilterLength+currentKeyValueLength)
			copy(newSlice, queryRequest.Query.BoolQuery.Filters[0:])
			queryRequest.Query.BoolQuery.Filters = newSlice
		}

		for _, filterValue := range currentFilterAssociation.Filters {
			queryRequest.Query.BoolQuery.Filters = append(
				queryRequest.Query.BoolQuery.Filters,
				&Filter{Term: filterValue},
			)
		}

		// Set defaults and source for Script.
		withScriptWithParams(queryRequest, script, scriptId, currentFilterAssociation)

		err := createBulkOperationItems(currentFilterAssociation, bulkOperationItems, false, scriptId)
		if err != nil {
			return err
		}

		queryRequest.BulkOperationItems = bulkOperationItems
	}

	return nil
}

func createBulkOperationItems[ParamArgsType AllParamConstraint](
	filterContext *FilterAssociation[ParamArgsType],
	bulkOperationItems *[]*BulkOperationItem[ParamArgsType],
	docAsUpsert bool,
	scriptId *string,
) error {
	const emptyString = ""
	var metadata ParamArgsType
	for _, item := range filterContext.bulkItems {
		upsert := NewBulkUpsert[ParamArgsType](
			item.LogContext,
			item.Index,
			false,
			emptyString,
			item.DocumentId,
			item.Document,
			metadata,
			nil,
			nil,
			nil,
			&docAsUpsert,
			item.TenantUuid,
			item.PublicSchemaVersion,
			item.PayloadSchemaName,
			item.EventMetadata,
			scriptId,
			nil,
			item.RoutingId,
		)

		*bulkOperationItems = append(
			*bulkOperationItems,
			upsert,
		)
	}

	return nil
}

// withShouldFilters adds multiple Filters to the given QueryRequest.
func withShouldFilters[ParamArgsType AllParamConstraint](
	queryRequest *QueryRequest[ParamArgsType],
	filters []*FilterAssociation[ParamArgsType],
	bulkOperationItems *[]*BulkOperationItem[ParamArgsType],
	script *string,
	scriptId *string,
) (*QueryRequest[ParamArgsType], error) {
	var (
		shouldBoolQueries []*ShouldQuery
		shouldBoolQuery   *ShouldQuery
	)

	queryRequest.
		withBool()

	for _, currentFilterAssociation := range filters {
		if currentFilterAssociation == nil {
			continue
		} else if !currentFilterAssociation.ArgType.Contains(CascadedDeleteArgType) &&
			!currentFilterAssociation.ArgType.Contains(SearchArgType) &&
			len(currentFilterAssociation.ParamArgs()) == 0 {
			const (
				msg           = "Filter Association has no parameters."
				filterListKey = "filter_list"
				argTypeKey    = "arg_type"
				stateKey      = "state"
			)

			log.Warnw(
				currentFilterAssociation.LogContext,
				msg,
				filterListKey, currentFilterAssociation.Filters,
				argTypeKey, currentFilterAssociation.ArgType,
				stateKey, currentFilterAssociation.state,
			)
			continue
		}

		if shouldBoolQueries == nil {
			shouldBoolQueries = make([]*ShouldQuery, 0, len(filters))
		}

		filterTerms := currentFilterAssociation.Filters
		filters := make([]*Filter, len(filterTerms))

		for currentFilterIndex, currentFilter := range filterTerms {
			filters[currentFilterIndex] = &Filter{
				Term: currentFilter,
			}
		}

		shouldBoolQuery = &ShouldQuery{
			BoolQueries: &BoolQuery{
				Filters: filters,
			},
		}

		shouldBoolQueries = append(shouldBoolQueries, shouldBoolQuery)

		if mustNotMatchCollection := currentFilterAssociation.MustNotMatch(); len(
			mustNotMatchCollection,
		) > 0 {
			shouldBoolQuery.BoolQueries.MustNot = []*mustNot{
				{Terms: mustNotMatchCollection},
			}
		}

		// Set defaults and source for Script.
		withScriptWithParams(queryRequest, script, scriptId, currentFilterAssociation)

		err := createBulkOperationItems(currentFilterAssociation, bulkOperationItems, true, scriptId)
		if err != nil {
			return queryRequest, err
		}

		queryRequest.BulkOperationItems = bulkOperationItems
	}

	if queryRequest.Query.BoolQuery.Filters == nil {
		queryRequest.Query.BoolQuery.Filters = []*Filter{
			{
				BoolQuery: &FilterBoolQuery{shouldBoolQueries},
			},
		}
	}

	return queryRequest, nil
}

