func createQueryRequests[ParamArgsType AllParamConstraint](
	logContext *log.Context,
	tenantUuid *string,
	filters filterContextCollection[ParamArgsType],
	filterFunc batchCallbackFunc[ParamArgsType],
	script *string,
	scriptId *string,
	query *string,
	nestingUpperLimit int,
) ([]*QueryRequest[ParamArgsType], error) {
	length := int(math.Ceil(float64(float32(filters.Count()) / float32(nestingUpperLimit))))

	queryRequests := make([]*QueryRequest[ParamArgsType], 0, length)
	for items := range filters.Chunk(nestingUpperLimit) {
		bulkItems := make([]*BulkOperationItem[ParamArgsType], 0, len(filters))

		// Create QueryRequest
		queryRequest, err := filterFunc(
			logContext,
			tenantUuid,
			query,
			items,
			&bulkItems,
			script,
			scriptId,
		)
		if err != nil {
			return queryRequests, err
		}

		queryRequests = append(queryRequests, queryRequest)
	}

	return queryRequests, nil
}

func createQueryRequest[ParamArgsType AllParamConstraint](
	logContext *log.Context,
	tenantUuid *string,
	query *string,
	filterContexts []*FilterAssociation[ParamArgsType],
	bulkOperationItems *[]*BulkOperationItem[ParamArgsType],
	script *string,
	scriptId *string,
) (*QueryRequest[ParamArgsType], error) {
	if tenantUuid == nil {
		return nil, nil
	}

	queryRequest := &QueryRequest[ParamArgsType]{}

	queryRequest.
		withQuery().
		withBool()

	queryRequest.LogContext = logContext

	// Setup Filters
	_ = queryRequest.
		WithFilter(map[string]any{tenantUuidString: tenantUuid})

	if len(filterContexts) > 0 {
		err := withFilters(queryRequest, filterContexts, bulkOperationItems, script, scriptId)
		if err != nil {
			return queryRequest, err
		}
	}

	// Add Query, if passed.
	if query != nil {
		queryRequest.
			WithMustMatchText(&textFieldName, query)
	}

	return queryRequest, nil
}

func createShouldQueryRequest[ParamArgsType AllParamConstraint](
	logContext *log.Context,
	_ *string,
	query *string,
	filters []*FilterAssociation[ParamArgsType],
	bulkOperationItems *[]*BulkOperationItem[ParamArgsType],
