		if err != nil {
			return queryRequest, err
		}

		queryRequest.LogContext = getLogContexts(filters)
	}

	// Add Query, if passed.
	if query != nil {
		queryRequest.
			WithMustMatchText(&textFieldName, query)
	}

	return queryRequest, nil
}

// FormatDuration converts a time.Duration to a string format understood by
// OpenSearch.
func FormatDuration(duration time.Duration) string {
	var builder strings.Builder

	days := duration / (24 * time.Hour)
	duration -= days * 24 * time.Hour
	hours := duration / time.Hour
	duration -= hours * time.Hour
	minutes := duration / time.Minute
	duration -= minutes * time.Minute
	seconds := duration / time.Second
	duration -= seconds * time.Second
	milliseconds := duration / time.Millisecond

	if days > 0 {
		fmt.Fprintf(&builder, "%dd", days)
	}
	if hours > 0 {
		fmt.Fprintf(&builder, "%dh", hours)
	}
	if minutes > 0 {
		fmt.Fprintf(&builder, "%dm", minutes)
	}
	if seconds > 0 {
		fmt.Fprintf(&builder, "%ds", seconds)
	}
	if milliseconds > 0 || builder.Len() == 0 {
		fmt.Fprintf(&builder, "%dms", milliseconds)
	}

	return builder.String()
}
