Modified version (after):
```go
func NewRangeQueryRequest[ParamArgsType AllParamConstraint](
    logContext *log.Context,
    termFilters []map[string]any,
    rangeFilters []map[string]*RangeFieldOperators,
    size int,
    sourceProperties []string,
    missingProperties []string,
) *QueryRequest[ParamArgsType] {
    queryRequest := &QueryRequest[ParamArgsType]{}
    queryRequest.withQuery().LogContext = logContext
    queryRequest.
        WithSize(size).
        WithSource(sourceProperties)

    queryRequest.withBool()

    for _, termFilter := range termFilters {
        queryRequest.WithFilter(termFilter)
    }

    shouldQueries := make([]*ShouldQuery, 0)
    if len(rangeFilters) > 0 {
        rangeQuery := &ShouldQuery{
            BoolQueries: &BoolQuery{
                Filters: make([]*Filter, 0, len(rangeFilters)),
            },
        }

        for _, rangeFilter := range rangeFilters {
            rangeQuery.BoolQueries.Filters = append(
                rangeQuery.BoolQueries.Filters,
                &Filter{Range: rangeFilter},
            )
        }
        shouldQueries = append(shouldQueries, rangeQuery)
    }

    if len(missingProperties) > 0 {
        for _, property := range missingProperties {
            shouldQueries = append(shouldQueries, &ShouldQuery{
                BoolQueries: &BoolQuery{
                    MustNot: []*mustNot{
                        {Exists: &exists{Field: &property}},
                    },
                },
            })
        }
    }

    if len(shouldQueries) > 0 {
        queryRequest.Query.BoolQuery.Should = shouldQueries
        minShouldMatch := 1
        queryRequest.Query.BoolQuery.MinimumShouldMatch = &minShouldMatch
    }

    return queryRequest
}
