type StaleEntityDetector interface {
	Start(context context.Context, logContext *log.Context)
	Stop()
	Done() <-chan struct{}
	DetectAndRemediate(
		logContext *log.Context,
		stalenessThreshold time.Duration,
		tenantUuid *string,
	)
}

type staleEntityDetector struct {
	driftDetector                       *driftDetector
	schemaMapper                        schemaMapping.SchemaMapper
	scheduler                           scheduler.Scheduler
	done                                chan struct{}
	client                              repository.NoSqlRepository
	defaultStalenessThreshold           string
	schedulerInterval                   time.Duration
	schedulerIntervalFormatted          string
	searchBatchSize                     int
	remediationRequestInterval          time.Duration
	staleEntitySearchRequiredProperties []string
	searchQueryRangeFilters             []map[string]*repository.RangeFieldOperators
}

func NewStaleEntityDetector(
	schemaMapper schemaMapping.SchemaMapper,
	scheduler scheduler.Scheduler,
	client repository.NoSqlRepository,
	remediationRequestEmitter emitter.RemediationRequestEmitter,
	schedulerInterval time.Duration,
	defaultStalenessThreshold time.Duration,
	searchBatchSize int,
	remediationRequestInterval time.Duration,
) StaleEntityDetector {
	return &staleEntityDetector{
		driftDetector: newDriftDetector(
			client,
			remediationRequestEmitter,
			remediationRequestInterval,
		),
		schemaMapper:                        schemaMapper,
		scheduler:                           scheduler,
		done:                                make(chan struct{}),
		client:                              client,
		schedulerInterval:                   schedulerInterval,
		schedulerIntervalFormatted:          repository.FormatDuration(schedulerInterval),
		defaultStalenessThreshold:           repository.FormatDuration(defaultStalenessThreshold),
		searchBatchSize:                     searchBatchSize,
		remediationRequestInterval:          remediationRequestInterval,
		staleEntitySearchRequiredProperties: []string{constants.UpdatedAt},
		searchQueryRangeFilters: []map[string]*repository.RangeFieldOperators{
			{
				constants.UpdatedAt: {
					LessThan: fmt.Sprintf("now-%s", repository.FormatDuration(defaultStalenessThreshold)),
				},
			},
		},
	}
}

func (s *staleEntityDetector) Start(context context.Context, logContext *log.Context) {
	const startingStaleEntityDetectorMessage = "stale_entity_detector.Start: starting scheduler for stale entity detector."

	log.Infow(logContext, startingStaleEntityDetectorMessage)

	// check for stale entities immediately and also start the scheduler to
	// monitor at regular interval.
	go s.remediateStaleEntities(logContext, nil, nil)

	s.scheduler.Start(
		context,
		func() { s.remediateStaleEntities(logContext, nil, nil) },
		s.schedulerInterval,
	)
}

func (s *staleEntityDetector) Stop() {
	s.scheduler.Stop()
	close(s.done)
}

func (s *staleEntityDetector) Done() <-chan struct{} {
	return s.done
}

func (s *staleEntityDetector) DetectAndRemediate(
	logContext *log.Context,
	stalenessThreshold time.Duration,
	tenantUuid *string,
) {
	const startingStaleEntityDetectorMessage = "stale_entity_detector.DetectAndRemediate: Detecting and remediating stale entities."

	log.Infow(logContext, startingStaleEntityDetectorMessage, log.TenantUuidKey, tenantUuid)

	threshold := repository.FormatDuration(stalenessThreshold)

	s.remediateStaleEntities(logContext, &threshold, tenantUuid)
}

// remediateStaleEntities identifies and remediates stale entities.
//
// This method detects and remediates entities that have become stale based on a
// specified threshold duration.
//
// Parameters:
//   - logContext: *log.Context - Used for logging operations and maintaining
//     context.
//   - entityStalenessThreshold: *string - Duration threshold for considering a
//     document as stale. If nil, uses the staleness threshold from the entity
//     remediation configuration.
//   - tenantUuid: *string - UUID of the tenant for which to perform
//     remediation.  If nil, search is performed across all tenants.
func (s *staleEntityDetector) remediateStaleEntities(
	logContext *log.Context,
	entityStalenessThreshold *string,
	tenantUuid *string,
) {
	const (
		functionName                          = "stale_entity_detector.remediateStaleEntities"
		skipEntityRemediationFeatureDisabled  = "stale_entity_detector.remediateStaleEntities: skipping remediation attempt on %s because the feature flag %s is disabled"
		startStaleEntityDetectionMessage      = "stale_entity_detector.remediateStaleEntities: starting stale entity detection and remediation."
		searchingForStaleEntities             = "stale_entity_detector.remediateStaleEntities: searching for %s entities older than %s"
		completedStaleEntityDetectionMessage  = "stale_entity_detector.remediateStaleEntities: completed stale entity detection and remediation. Waiting for next schedule in %s."
		errorOccurredWhileRemediatingEntities = "stale_entity_detector.remediateStaleEntities: Error occurred when remediating entity %s"
	)

	var (
		indexMetadata *schemaMapping.IndexMetadata
		err           error
	)

	defer errorHandling.Recover(logContext, nil)

	log.Infow(logContext, startStaleEntityDetectionMessage, log.TenantUuidKey, tenantUuid)

	var stalenessThreshold string

	for indexKey, remediationConfig := range s.schemaMapper.GetIndexRemediationConfigMap() {
		if remediationConfig == nil {
			continue
		}

		if remediationConfig.FeatureFlag != nil && !ff.IsEnabled(*remediationConfig.FeatureFlag, false) {
			log.Warnw(
				logContext,
				fmt.Sprintf(
					skipEntityRemediationFeatureDisabled,
					indexKey,
					*remediationConfig.FeatureFlag,
				),
			)

			continue
		}
		if entityStalenessThreshold != nil {
			stalenessThreshold = *entityStalenessThreshold
		} else if remediationConfig.StalenessThreshold != nil {
			stalenessThreshold = *remediationConfig.StalenessThreshold
		} else {
			stalenessThreshold = s.defaultStalenessThreshold
		}

		indexMetadata, _ = s.schemaMapper.GetIndexMetadataByIndexKey(indexKey)

		query := s.createStaleEntitySearchQuery(
			logContext,
			tenantUuid,
			indexKey,
			indexMetadata.KeyProperties,
			stalenessThreshold,
		)

		log.Infow(
			logContext,
			fmt.Sprintf(searchingForStaleEntities, remediationConfig.EntitySchemaName, stalenessThreshold),
			log.TenantUuidKey,
			tenantUuid,
		)

		err = s.driftDetector.detectAndRemediateDrift(
			logContext,
			functionName,
			remediationConfig.EntitySchemaName,
			remediationConfig,
			tenantUuid,
			query,
		)

		if err != nil {
			// log and move to the next entity
			log.Errorw(
				logContext,
				fmt.Sprintf(errorOccurredWhileRemediatingEntities, remediationConfig.EntitySchemaName),
				log.ErrorKey,
				err,
				log.TenantUuidKey,
				tenantUuid,
				log.EntityNameKey,
				remediationConfig.EntitySchemaName,
				log.ErrorResponse,
				errorHandling.GetData[*repository.AnyResponse](err),
			)
		}
	}

	log.Infof(logContext, completedStaleEntityDetectionMessage, s.schedulerIntervalFormatted)
}

// createStaleEntitySearchQuery creates a query to search for stale entities in
// the sequence number index for entities with remediation config.
func (s *staleEntityDetector) createStaleEntitySearchQuery(
	logContext *log.Context,
	tenantUuid *string,
	indexKey string,
	properties []string,
	stalenessThreshold string,
) *repository.QueryDetailsItem[*repository.QueryRequest[repository.Params]] {
	termFilters := []map[string]any{}

	if tenantUuid != nil {
		termFilters = []map[string]any{
			{tenantUuidPropertyName: tenantUuid},
		}
	}

	s.searchQueryRangeFilters[0][constants.UpdatedAt].LessThan = fmt.Sprintf("now-%s", stalenessThreshold)

	// TODO: Add check for when updated_at property is missing
	queryBody := repository.NewRangeQueryRequest[repository.Params](
		logContext,
		termFilters,
		s.searchQueryRangeFilters,
		s.searchBatchSize,
		properties,
		s.staleEntitySearchRequiredProperties,
	)

	queryBody.WithSort(map[string]string{"_id": "asc"})

	query := &repository.QueryDetailsItem[*repository.QueryRequest[repository.Params]]{
		Indices:    []string{indexKey},
		Body:       queryBody,
		LogContext: queryBody.LogContext,
	}

	return query
}
