	return &driftDetector{
		client:                     client,
		remediationRequestEmitter:  remediationRequestEmitter,
		remediationRequestInterval: remediationRequestInterval,
	}
}

func (d *driftDetector) detectAndRemediateDrift(
	logContext *log.Context,
	callingFunctionName string,
	entityName string,
	remediationConfig *schemaMapping.RemediationConfig,
	tenantUuid *string,
	query *repository.QueryDetailsItem[*repository.QueryRequest[repository.Params]],
) error {
	const (
		errorOccurredWhenSearchingForDriftedEntities           = "%s: drift_detector.detectAndRemediateDrift: Error occurred during searching for drifted entity %s"
		noMoreDriftedEntitiesFoundToRemediate                  = "%s: drift_detector.detectAndRemediateDrift: End of page, or no more drifted %s entity found to remediate"
		foundDriftedEntitiesToRemediate                        = "%s: drift_detector.detectAndRemediateDrift: Found %d %s drifted entities to remediate"
		errorOccurredWhenRequestingFullStateForDriftedEntities = "%s: drift_detector.detectAndRemediateDrift: Error occurred when requesting full state for drifted entity %s"
		fetchingNextBatchOfStaleEntities                       = "%s: drift_detector.detectAndRemediateDrift: More stale %s entities are present, waiting %s before fetching next batch."
	)

	defer errorHandling.Recover(logContext, nil, log.EntityNameKey, entityName)

	// TODO: Fix all comments to ensure they don't have the word stale and they are generic
	// fetch a batch of stale entities and remediate them before fetching
	// the next batch
	var (
		searchResponse *repository.SearchQueryResponse[map[string]any]
		staleEntities  []*repository.Hit[map[string]any]
		err            error
	)

	for {
		remediationBatchCorrelationId := uuid.NewString()
		searchResponse, err = d.executeSearchQuery(logContext, query)
		if err != nil {
			return errors.Wrapf(err, errorOccurredWhenSearchingForDriftedEntities, callingFunctionName, entityName)
		}

		if searchResponse == nil || searchResponse.Hits == nil || len(searchResponse.Hits.Hits) == 0 {
			// nothing to remediate
			log.Infow(
				logContext,
				fmt.Sprintf(noMoreDriftedEntitiesFoundToRemediate, callingFunctionName, entityName),
				log.TenantUuidKey,
				tenantUuid,
				log.EntityNameKey,
				entityName,
				remediationBatchCorrelationIdKey,
				remediationBatchCorrelationId,
			)
			return nil
		}

		staleEntities = searchResponse.Hits.Hits

		log.Infow(
			logContext,
			fmt.Sprintf(foundDriftedEntitiesToRemediate, callingFunctionName, len(staleEntities), entityName),
			log.TenantUuidKey,
			tenantUuid,
			log.EntityNameKey,
			entityName,
			remediationBatchCorrelationIdKey,
			remediationBatchCorrelationId,
		)

		err := d.requestFullStateEventsForDriftedEntities(
			logContext,
			callingFunctionName,
			remediationBatchCorrelationId,
			remediationConfig,
			staleEntities,
		)
		if err != nil {
			return errors.Wrapf(
				err,
				errorOccurredWhenRequestingFullStateForDriftedEntities,
				callingFunctionName,
				entityName,
			)
		}

		telemetry.Count(
			logContext,
			group.DriftDetection,
			metric.RemediatedEntitiesCount,
			int64(len(staleEntities)),
			metrics.NewTag(telemetry.EntityNameTag, entityName),
		)

		searchAfter := staleEntities[len(staleEntities)-1].Sort
		if searchAfter == nil {
			break
		}

		// Add delay before making the next call
		query.Body.WithSearchAfter(searchAfter)

		log.Infow(
			logContext,
			fmt.Sprintf(
				fetchingNextBatchOfStaleEntities,
				callingFunctionName,
				entityName,
				d.remediationRequestInterval,
			),
		)
		time.Sleep(d.remediationRequestInterval)
	}

	return nil
}

func (d *driftDetector) executeSearchQuery(
	logContext *log.Context,
	query *repository.QueryDetailsItem[*repository.QueryRequest[repository.Params]],
) (*repository.SearchQueryResponse[map[string]any], error) {
	const (
		functionName                              = "drift_detector.getStaleEntitiesBatch"
		errorOccurredWhenSearchingDriftedEntities = "drift_detector.getStaleEntitiesBatch: Error occurred during searching for drifted entities"
		failedToDecodeResponse                    = "drift_detector.getStaleEntitiesBatch: failed to decode search response"
	)

	res, err := d.client.Search(logContext, query)
	if err != nil {
		return nil, errors.Wrap(err, errorOccurredWhenSearchingDriftedEntities)
	}

	searchResponse := &repository.SearchQueryResponse[map[string]any]{}
	err = jsoniter.NewDecoder(res.Response).Decode(searchResponse)
	if err != nil {
		return nil, errors.Wrap(err, failedToDecodeResponse)
	}

	return searchResponse, nil
}

func (d *driftDetector) requestFullStateEventsForDriftedEntities(
	logContext *log.Context,
	callingFunctionName string,
	remediationBatchCorrelationId string,
	remediationConfig *schemaMapping.RemediationConfig,
	documents []*repository.Hit[map[string]any],
) error {
	const (
		remediationSourceUrlNotDefined         = "%s: drift_detector.requestFullStateEventsForDriftedEntities: remediation source %s is not defined."
		failedToConstructRemediationApiUrl     = "%s: drift_detector.requestFullStateEventsForDriftedEntities: failed to construct remediation API url. Base url: %s, API url: %s"
		initiatingRemediationRequestLogMessage = "%s: drift_detector.requestFullStateEventsForDriftedEntities: initiating remediation request for entities."
		noEntityKeyPresentForDocLogMessage     = "%s: drift_detector.requestFullStateEventsForDriftedEntities: the drifted document for %s entity doesn't contain entity key properties"
		noFullStateRequestsCreatedLogMessage   = "%s: drift_detector.requestFullStateEventsForDriftedEntities: there are %d documents, but no full state requests were created."
		failedToEmitFullStateRequestLogMessage = "%s: drift_detector.requestFullStateEventsForDriftedEntities: Full state request failed."
		remediationRequestsKey                 = "remediation_requests"
	)

	var (
		tenantFullStateRequest = make(map[string]*uemApiClient.FullStateApiRequestModel)
		fullStateRequests      = make([]*uemApiClient.FullStateApiRequestModel, 0, 1)
		tenantUuid             string
		entityUniqueKeys       map[string]string
		apiUrl                 string
		err                    error
		ok                     bool
	)

	// figure out the source service url
	if apiUrl, ok = serviceLocationEnvToApiUrlMap[remediationConfig.ServiceUrlLookupEnv]; !ok {
		basePath := env.GetValue(logContext, remediationConfig.ServiceUrlLookupEnv)
		apiUrl, err = url.JoinPath(
			basePath,
			remediationConfig.ApiUrl,
		)
		if err != nil {
			log.Errorw(
				logContext,
				fmt.Sprintf(
					failedToConstructRemediationApiUrl,
					callingFunctionName,
					basePath,
					remediationConfig.ApiUrl,
				),
				log.ErrorKey,
				err,
			)

			return errors.Wrapf(
				err,
				remediationSourceUrlNotDefined,
				callingFunctionName,
				remediationConfig.ServiceUrlLookupEnv,
			)
		}

		serviceLocationEnvToApiUrlMap[remediationConfig.ServiceUrlLookupEnv] = apiUrl
	}

	for _, document := range documents {
		if document.Source == nil {
			continue
		}

		tenantUuid, entityUniqueKeys = extractEntityKeyProperties(
			remediationConfig.KeyProperties,
			document.Source,
		)

		if tenantUuid == "" || len(entityUniqueKeys) == 0 {
			log.Warnw(
				logContext,
				fmt.Sprintf(
					noEntityKeyPresentForDocLogMessage,
					callingFunctionName,
					remediationConfig.EntitySchemaName,
				),
				"drifted_doc",
				document,
				remediationBatchCorrelationIdKey,
				remediationBatchCorrelationId,
			)
			continue
		}

		var fullStateRequestModel *uemApiClient.FullStateApiRequestModel

		if fullStateRequestModel, ok = tenantFullStateRequest[tenantUuid]; !ok {
			fullStateRequestModel = &uemApiClient.FullStateApiRequestModel{
				CorrelationId:               remediationBatchCorrelationId,
				SourceEndpointTagMetricName: remediationConfig.ServiceUrlLookupEnv,
				ApiUrl:                      apiUrl,
				TokenServiceClientId:        env.GetValue(logContext, remediationConfig.TokenServiceClientIdLookupEnv),
				TokenServiceClientSecret: env.GetValue(
					logContext,
					remediationConfig.TokenServiceClientSecretLookupEnv,
				),
				ClientId:   pkg.ClientIdHeaderExpectedValue,
				TenantUuid: tenantUuid,
				Entities:   make([]*uemApiClient.Entity, 0, len(documents)),
			}
			tenantFullStateRequest[tenantUuid] = fullStateRequestModel
			fullStateRequests = append(fullStateRequests, fullStateRequestModel)
		}

		fullStateRequestModel.Entities = append(fullStateRequestModel.Entities, &uemApiClient.Entity{
			SchemaName: remediationConfig.EntitySchemaName,
			TenantUuid: &tenantUuid,
			UniqueKeys: entityUniqueKeys,
		})
	}

	if len(fullStateRequests) == 0 {
		log.Warnw(
			logContext,
			fmt.Sprintf(noFullStateRequestsCreatedLogMessage, callingFunctionName, len(documents)),
			"drifted_docs",
			documents,
			remediationBatchCorrelationIdKey,
			remediationBatchCorrelationId,
		)

		return nil
	}

	log.Infow(
		logContext,
		fmt.Sprintf(initiatingRemediationRequestLogMessage, callingFunctionName),
		remediationRequestsKey,
		fullStateRequests,
		remediationBatchCorrelationIdKey,
		remediationBatchCorrelationId,
	)

	_, err = d.remediationRequestEmitter.RequestFullStateEvents(logContext, fullStateRequests)
	if err != nil {
		return errors.Wrapf(err, failedToEmitFullStateRequestLogMessage, callingFunctionName)
	}

	return nil
}

// extractEntityKeyProperties extracts the tenant UUID and key properties from the given document.
//
// Parameters:
//   - indexEntityKeyPropertiesMap: []*schemaMapping.SourceTargetFieldMap - Mapping of source to target fields for the index entity.
//   - document: map[string]any - The document from which to extract the properties.
//
// Returns:
//   - string - The tenant UUID extracted from the document.
//   - map[string]string - A map of target field names to their corresponding values extracted from the document.
func extractEntityKeyProperties(
	indexEntityKeyPropertiesMap []*schemaMapping.SourceTargetFieldMap,
	document map[string]any,
) (string, map[string]string) {
	tenantUuid, _ := document[tenantUuidPropertyName].(string)
	keyPropertyMap := make(map[string]string, len(indexEntityKeyPropertiesMap))

	for _, property := range indexEntityKeyPropertiesMap {
		if value, ok := document[property.SourceFieldName].(string); ok {
			keyPropertyMap[property.TargetFieldName] = value
		}
	}

	return tenantUuid, keyPropertyMap
}
