			),
			generator.CreateStringListAttributeChange(
				"uem.device.parent_organization_group_uuids",
				mockDataGenerator.Create,
				device.ParentOrganizationGroupUuids,
			),
			generator.CreateIntAttributeChange(
				"uem.device.type",
				mockDataGenerator.Create,
				int32(device.Type),
			),
			generator.CreateAttributeChange(
				"uem.device.enrollment_user_uuid",
