        LogContext: queryBody.LogContext,
    }
}

func (d *baseDriftDetector[T]) DetectAndRemediate(
    logContext *log.Context,
    params T,
    tenantUuid *string,
) {
    const functionName = "DetectAndRemediate"

    defer errorHandling.Recover(logContext, nil)

    log.Infow(logContext, fmt.Sprintf(startDetectionMessage, functionName), log.TenantUuidKey, tenantUuid)

    for indexKey, remediationConfig := range d.schemaMapper.GetIndexRemediationConfigMap() {
        if remediationConfig == nil {
            continue
        }

        if remediationConfig.FeatureFlag != nil && !ff.IsEnabled(*remediationConfig.FeatureFlag, false) {
            log.Warnw(
                logContext,
                fmt.Sprintf(
                    skipRemediationFeatureDisabled,
                    functionName,
                    indexKey,
                    *remediationConfig.FeatureFlag,
                ),
            )
            continue
        }

        indexMetadata, _ := d.schemaMapper.GetIndexMetadataByIndexKey(indexKey)

        query := params.CreateQuery(
            logContext,
            tenantUuid,
            indexKey,
            indexMetadata.KeyProperties,
            d.searchBatchSize,
        )

        log.Infow(
            logContext,
            fmt.Sprintf(searchingMessage, functionName, remediationConfig.EntitySchemaName),
            log.TenantUuidKey,
            tenantUuid,
        )

        err := d.detectAndRemediateDrift(
            logContext,
            functionName,
            remediationConfig.EntitySchemaName,
            remediationConfig,
            tenantUuid,
            query,
        )

        if err != nil {
            log.Errorw(
                logContext,
                fmt.Sprintf(errorOccurredMessage, functionName, remediationConfig.EntitySchemaName),
                log.ErrorKey,
                err,
                log.TenantUuidKey,
                tenantUuid,
                log.EntityNameKey,
                remediationConfig.EntitySchemaName,
                log.ErrorResponse,
                errorHandling.GetData[*repository.AnyResponse](err),
            )
        }
    }

    log.Infof(logContext, completedDetectionMessage, functionName, d.schedulerIntervalFormatted)
}
