// stale_entity_detector.go
type StaleEntityParams struct {
    defaultStalenessThreshold string  // rename to make it clear this is default
    RequiredProperties []string
    RangeFilters       []map[string]*repository.RangeFieldOperators
}

func (p StaleEntityParams) CreateQuery(
    logContext *log.Context,
    tenantUuid *string,
    indexKey string,
    indexMetadata *schemaMapping.IndexMetadata,
    remediationConfig *schemaMapping.RemediationConfig,
    searchBatchSize int,
) *repository.QueryDetailsItem[*repository.QueryRequest[repository.Params]] {
    // Use remediationConfig threshold if available, otherwise use default/test threshold
    stalenessThreshold := p.defaultStalenessThreshold
    if remediationConfig.StalenessThreshold != nil {
        stalenessThreshold = *remediationConfig.StalenessThreshold
    }

    // Create a copy of range filters with updated threshold
    rangeFilters := make([]map[string]*repository.RangeFieldOperators, len(p.RangeFilters))
    copy(rangeFilters, p.RangeFilters)
    rangeFilters[0][constants.UpdatedAt].LessThan = fmt.Sprintf("now-%s", stalenessThreshold)

    termFilters := []map[string]any{}
    if tenantUuid != nil {
        termFilters = []map[string]any{{tenantUuidPropertyName: tenantUuid}}
    }

    queryBody := repository.NewRangeQueryRequest[repository.Params](
        logContext,
        termFilters,
        rangeFilters,  // use the copy with updated threshold
        searchBatchSize,
        indexMetadata.KeyProperties,
        p.RequiredProperties,
    )

    queryBody.WithSort(map[string]string{"_id": "asc"})

    return &repository.QueryDetailsItem[*repository.QueryRequest[repository.Params]]{
        Indices:    []string{indexKey},
        Body:       queryBody,
        LogContext: queryBody.LogContext,
    }
}

// Update method for testing
func (p StaleEntityParams) WithStalenessThreshold(threshold time.Duration) StaleEntityParams {
    p.defaultStalenessThreshold = repository.FormatDuration(threshold)
    return p
}
