	scriptsDir            string
	telemetryConfigPath   string
)

func init() {
	logContext := log.NewLogContextWithCorrelationIds(uuid.NewString())

	logContextFunc := func() *log.Context {
		return logContext
	}

	defer errorHandling.LogPanicAndExit(logContextFunc)

	flag.StringVar(&rootDir, "rootDir", "./", "Root directory where OpenSearch files are located.")
	flag.StringVar(
		&mappingConfigPath,
		"mappingConfigPath",
		schemaMapping.DefaultMappingConfigPath,
		"Path to the schema mapping configuration file.",
	)
	flag.StringVar(
		&indexConfigFilePath,
		"indexConfigFilePath",
		opensearchInternal.DefaultIndexConfigFilePath,
		"Path to the index config file.",
	)
	flag.StringVar(
		&indexDependenciesPath,
		"indexDependenciesPath",
		"configs/"+dependencies.DefaultDependenciesFilename,
		"Path to the index dependencies configuration file.",
	)
	flag.StringVar(
		&scriptsDir,
		"scripts",
		opensearchInternal.DefaultSchemaRootDirPath,
		"Path to indices, templated-scripts, and queries.",
	)
	flag.StringVar(
		&telemetryConfigPath,
		"telemetryConfigPath",
		"configs/telemetry.yaml",
		"Path to the telemetry configuration file.",
	)
	flag.Parse()

	// Only load exact environment files.
	err := godotenv.Load(projectPaths.DotEnv)
	errorHandling.HandleWarning(logContext, errors.Wrap(err, "main.init"))

	// initialize logger
	log.SetLevel(env.LookupValue(log.LogLevelEnvKey, log.InfoLevel))
	log.InitializeLogger(false, map[string]string{pkg.StartUpKey: "remediation"})

	helpers.SetLogLevelsFromFeatureFlags()

	log.Infow(
		logContext,
		fmt.Sprintf(
			"Omnissa Gumdrop Ingestion v%s, (c) %v Omnissa, LLC. All rights reserved.",
			version.Version,
			time.Now().UTC().Year(),
		),
		log.SupportedPublicSchemaVersionKey, version.SchemaVersion,
	)

	go func() {
		errorHandling.HandleError(logContextFunc, http.ListenAndServe("localhost:6060", nil))
	}()

	startUp = createRemediationStartup(logContext)
}

func main() {
	defer log.Flush()
	defer startUp.Close()
	<-startUp.Done()
}

func createRemediationStartup(logContext *log.Context) cmd.RemediationStartup {
	var (
		auditLogBatchSize = env.LookupIntValue(
			logContext,
			pkg2.AuditLogBatchSizeEnv,
			pkg2.DefaultAuditLogBatchSize,
		)
		httpRequestTimeout time.Duration = time.Duration(env.LookupIntValue(
			logContext,
			pkg.HttpClientRequestTimeoutSecondsEnv,
			30,
		)) * time.Second
		transientErrorRetryClientMaxAttempts int = env.LookupIntValue(
			logContext,
			pkg.TransientErrorRetryMaxAttemptsEnv,
			5,
		)
		transientErrorRetryClientBaseDelay time.Duration = time.Duration(env.LookupIntValue(
			logContext,
			pkg.TransientErrorRetryBaseDelayMillisecondsEnv,
			100,
		)) * time.Millisecond
		transientErrorRetryClientMaxDelay time.Duration = time.Duration(env.LookupIntValue(
			logContext,
			pkg.TransientErrorRetryMaxDelaySecondsEnv,
			10,
		)) * time.Second
		httpClient                = &http.Client{Timeout: httpRequestTimeout}
		transientErrorRetryClient = &retry.Client{
			MaxAttempts: transientErrorRetryClientMaxAttempts,
			BaseDelay:   transientErrorRetryClientBaseDelay,
			MaxDelay:    transientErrorRetryClientMaxDelay,
			CanRetry:    errorHandling.IsTransientNetworkError,
		}
		// cache client for storing tokens
		bigCacheClient, _   = bigCache.New(context.Background(), cmd.NewCacheSettingFromEnv(logContext))
		cacheStore          = cacheStore.NewBigcache(bigCacheClient)
		cacheImplementation = cache.New[[]byte](cacheStore)

		// YATS client
		accessTokenProvider = uemApiClient.NewYatsAccessTokenProvider(
			httpClient,
			transientErrorRetryClient,
			cacheImplementation,
		)

		uemRemediationApiClient = uemApiClient.NewUemRemediationApiClient(
			logContext,
			httpClient,
			transientErrorRetryClient,
			env.GetValue(logContext, pkg.TokenServiceUrlEnv),
			accessTokenProvider,
			&uemApiClient.UemRemediationApiClientConfig{
				UserAgent: fmt.Sprintf(
					"%s/%s (env=%s; ldd=%s; alloc_name=%s; alloc_id=%s)",
					version.ServiceName,
					version.Version,
					env.LookupValue(pkg.DataCenterNameEnv, ""),
					env.LookupValue(pkg.DeploymentNameEnv, ""),
					env.LookupValue(pkg.AllocationNameEnv, ""),
					env.LookupValue(pkg.AllocationIdEnv, ""),
				),
			},
		)

		remediationRequestEmitter = emitter.NewRemediationRequestEmitter(
			transientErrorRetryClient,
			uemRemediationApiClient,
			auditLogBatchSize,
		)
	)

	return startup.NewRemediationStartup(
		logContext,
		&startup.RemediationParameter{
			RootDir:                           rootDir,
			ScriptRootDir:                     scriptsDir,
			MappingConfigPath:                 mappingConfigPath,
			IndexDependenciesPath:             indexDependenciesPath,
			IndexConfigFilePath:               indexConfigFilePath,
			TelemetryConfigPath:               telemetryConfigPath,
			MainApp:                           true,
			ApiRouteBasePath:                  remediationAppApiBasePath,
			UemRemediationApiClient:           uemRemediationApiClient,
			RemediationRequestEmitter:         remediationRequestEmitter,
			StartStaleEntityDetector:          feature_flag.EnableStaleEntityRemediation.IsEnabled(),
			StartIndexMissingPropertyDetector: feature_flag.EnableIndexMissingPropertyRemediation.IsEnabled(),
		},
	)
}
