	opensearchShared "airwatch/uem/gumdrop-ingestion/pkg/repository/opensearch-pkg"
	"airwatch/uem/gumdrop-ingestion/pkg/telemetry"
)

// remediationStartup struct holding startup dependencies.
type remediationStartup struct {
	opensearchClient    repository.NoSqlReadRepository
	doneChannel         <-chan struct{}
	ctx                 context.Context
	cancelFunc          context.CancelFunc
	schemaMapper        schemaMapping.SchemaMapper
	staleEntityDetector driftDetection.StaleEntityDetector
}

type RemediationParameter struct {
	RootDir                           string
	ScriptRootDir                     string
	MappingConfigPath                 string
	IndexDependenciesPath             string
	IndexConfigFilePath               string
	TelemetryConfigPath               string
	MainApp                           bool
	StartStaleEntityDetector          bool
	StartIndexMissingPropertyDetector bool
	ApiRouteBasePath                  string
	UemRemediationApiClient           uemApiClient.RemediationApiClient
	RemediationRequestEmitter         emitter.RemediationRequestEmitter
	AuditLogBatchSize                 int
}

// NewRemediationStartup starts the remediation application.
func NewRemediationStartup(
	logContext *log.Context,
	startupParameter *RemediationParameter,
) cmd.RemediationStartup {
	const functionName = "startup.NewRemediationStartup"

	// Start API Service
	if startupParameter.MainApp {
		go api.Start(
			logContext,
			os.Getenv(api.ListeningAddr),
			startupParameter.ApiRouteBasePath,
			fmt.Sprintf(
				"%s%c%s",
				env.LookupValue(pkg2.TempFolderPathEnv, projectPaths.TempFolderPath),
				filepath.Separator,
				"remediation",
			),
		)
	}

	logContextFunc := func() *log.Context {
		return logContext
	}

	// Initialize Telemetry
	enableTelemetry := env.LookupBoolValue(logContext, pkg2.EnableTelemetryEnv, true)
	if enableTelemetry {
		startUpTag := fmt.Sprintf("%s:%s", pkg2.StartUpKey, "remediation")
		_ = errorHandling.HandleError(
			logContextFunc,
			telemetry.InitRegistryFromFile(
				logContext,
				startupParameter.TelemetryConfigPath,
				&startUpTag,
			),
		)
	}

	opensearchAddresses := strings.Split(
		os.Getenv(databaseConstants.OpenSearchServer),
		",",
	)

	if startupParameter.StartStaleEntityDetector {
		// Wait for containers.
		helpers.WaitForIt(logContext, startupParameter.RootDir, opensearchAddresses[0])
	}

	indexPropertyKeyMap, indexKeyToIndexDefinitionMap, indexKeyToIndexAliasMap, indexAliasOrIndexNameToIndexKeyMap := repository.ReadIndexPropertiesFromDefinitions(
		logContext,
		path.Join(startupParameter.ScriptRootDir, "indices"),
		startupParameter.IndexConfigFilePath,
	)

	indexDependencies, err := dependencies.LoadIndexDependencies(
		startupParameter.IndexDependenciesPath,
	)

	errorHandling.HandleFatal(
		logContext,
		errors.Wrap(err, functionName),
	)

	var indexKeyToIndexNameMap map[string]string
	consulClient := consul.NewConsulClient(logContext)
	synchClient := synchClients.NewSynchronizationClient(
		consulClient,
		pkg.DatabaseVersionConsulKey,
		pkg.LegacyDatabasePauseConsulKey,
	)
	bypassDbVersionCheck := env.LookupBoolValue(logContext, databaseConstants.OpenSearchBypassVersionCheck, false)

	if !bypassDbVersionCheck {
		helpers.WaitForIt(logContext, startupParameter.RootDir, consulClient.Address())
		synchClient.WaitForPublish(logContext)
	}

	tmpSchemaMapper := schemaMapping.NewSchemaMapper(
		logContext,
		startupParameter.MappingConfigPath,
		indexPropertyKeyMap,
		indexDependencies,
		indexKeyToIndexAliasMap,
		indexAliasOrIndexNameToIndexKeyMap,
		nil,
	)

	opensearchMgmtClient := opensearchShared.NewOpenSearchMgmtClient(
		logContext,
		nil,
		indexKeyToIndexDefinitionMap,
		synchClient,
		tmpSchemaMapper,
	)

	indexAliasOrIndexNameToIndexKeyMap, indexKeyToIndexAliasMap, indexKeyToIndexNameMap, err = opensearchMgmtClient.GetIndexAndAliasMaps(
		logContext,
	)

	errorHandling.HandleFatal(
		logContext,
		errors.Wrap(err, functionName),
	)

	applicationInfo.PublishFinished = true

	schemaMapper := telemetry.MeasureWithResult(
		logContext,
		group.Config,
		metric.LoadSchemaMapping,
		func() schemaMapping.SchemaMapper {
			return schemaMapping.NewSchemaMapper(
				logContext,
				startupParameter.MappingConfigPath,
				indexPropertyKeyMap,
				indexDependencies,
				indexKeyToIndexAliasMap,
				indexAliasOrIndexNameToIndexKeyMap,
				indexKeyToIndexNameMap,
			)
		},
	)

	opensearchClient, err := opensearchShared.NewOpenSearchClient(
		logContext,
		opensearchAddresses,
		nil,
		false,
		indexKeyToIndexAliasMap,
		nil,
		nil,
	)
	errorHandling.HandleFatal(
		logContext,
		errors.Wrap(err, functionName),
	)

	ctx := context.WithValue(context.Background(), log.LogContextKey, logContext)
	ctx, cancelFunc := context.WithCancel(ctx)

	staleEntityDetector := driftDetection.NewStaleEntityDetector(
		schemaMapper,
		scheduler.NewSimpleScheduler(),
		opensearchClient,
		startupParameter.RemediationRequestEmitter,
		// 16 hours if not specified
		time.Duration(
			env.LookupIntValue(logContext, pkg2.StaleEntityCheckIntervalMinutesEnv, 960),
		)*time.Minute,
		// 16 hours if not specified
		time.Duration(
			env.LookupIntValue(
				logContext,
				pkg2.DefaultEntityStalenessThresholdHoursEnv,
				pkg2.DefaultStaleDocumentThresholdHours,
			),
		)*time.Hour,
		env.LookupIntValue(
			logContext,
			pkg2.StaleEntitySearchBatchSizeEnv,
			pkg2.DefaultSearchPageSizeLimit,
		),
		time.Duration(
			env.LookupIntValue(
				logContext,
				pkg2.RemediationRequestIntervalSecondsEnv,
				pkg2.DefaultRemediationRequestIntervalSeconds,
			),
		)*time.Second,
	)

	if startupParameter.StartStaleEntityDetector {
		staleEntityDetector.Start(ctx, logContext)
	}

	// All parameters are set.
	// Create remediationStartup for the caller.
	stUp := &remediationStartup{
		opensearchClient:    opensearchClient,
		doneChannel:         staleEntityDetector.Done(),
		ctx:                 ctx,
		cancelFunc:          cancelFunc,
		schemaMapper:        schemaMapper,
		staleEntityDetector: staleEntityDetector,
	}

	return stUp
}

// Done returns done channel for consumer.
func (startup *remediationStartup) Done() <-chan struct{} {
	return startup.doneChannel
}

// Close cancels the consumer context.
func (startup *remediationStartup) Close() {
	startup.staleEntityDetector.Stop()
	startup.cancelFunc()
}

// ReadProvider returns repository.NoSqlReadRepository for querying data.
func (startup *remediationStartup) ReadProvider() repository.NoSqlReadRepository {
	return startup.opensearchClient
}

// SchemaMapper returns the current schema mapper interface.
func (startup *remediationStartup) SchemaMapper() schemaMapping.SchemaMapper {
	return startup.schemaMapper
}

func (startup *remediationStartup) StaleEntityDetector() driftDetection.StaleEntityDetector {
	return startup.staleEntityDetector
}
