	"airwatch/uem/gumdrop-ingestion/pkg/streaming"
	"airwatch/uem/gumdrop-ingestion/pkg/streaming/kafka"
	"airwatch/uem/gumdrop-ingestion/pkg/telemetry"
)

const (
	saramaMetricPrefix = "sarama"
)

// ingestStartup struct holding startup dependencies.
type ingestStartup struct {
	opensearchClient  repository.NoSqlReadRepository
	doneChannel       <-chan struct{}
	ctx               context.Context
	cancelFunc        context.CancelFunc
	dlqProducer       streaming.Producer[*streaming.EventDiscard]
	schemaMapper      schemaMapping.SchemaMapper
	messageProcessor  processor.Processor
	openSearchEmitter emitter.Emitter
}

type Parameter struct {
	StartUp                 string
	RootDir                 string
	ScriptRootDir           string
	KafkaBrokers            []string
	KafkaConsumerTopics     []string
	KafkaProducerTopics     map[string][]string
	KafkaVersion            string
	BatchPartitionCount     int
	BatchSize               int
	AuditLogBatchSize       int
	BatchDocsThreshold      int
	ClientId                string
	MappingConfigPath       string
	IndexDependenciesPath   string
	IndexConfigFilePath     string
	Refresh                 bool
	KafkaConnectionMaxRetry int
	QueueTimeout            time.Duration
	TelemetryConfigPath     string
	DLQKafkaTopics          []string
	DLQClientId             string
	EnableConsumer          bool
	MainApp                 bool
	UpdateByQueryScrollSize *int
	UpdateByQuerySlices     interface{}
	FanOutKafkaTopics       []string
	FanOutClientId          string
	ProcessOnlyFanOut       bool
	ApiRouteBasePath        string
	BatchPartitioner        func(processor.Processor) partitioner.Partitioner[*transform.MessageModel]
	MessageFilterCtor       func(schemaMapping schemaMapping.SchemaMapper) filter.MessageFilter
	MessageProcessorCtor    func(
		logContext *log.Context,
		dependencies *processor.MessageProcessorDependencies,
		auditLogBatchSize int,
	) processor.Processor
	UemRemediationApiClient   uemApiClient.RemediationApiClient
	RemediationRequestEmitter emitter.RemediationRequestEmitter
	IgnoreDriftDetection      bool
}

// NewIngestionStartup starts the consumer application.
func NewIngestionStartup(
	logContext *log.Context,
	startupParameter *Parameter,
) cmd.Startup {
	const functionName = "startup.NewIngestionStartup"

	// Start API Service
	if startupParameter.MainApp {
		go api.Start(
			logContext,
			os.Getenv(api.ListeningAddr),
			startupParameter.ApiRouteBasePath,
			fmt.Sprintf(
				"%s%c%s",
				env.LookupValue(pkg2.TempFolderPathEnv, projectPaths.TempFolderPath),
				filepath.Separator,
				startupParameter.StartUp,
			),
		)
	}

	logContextFunc := func() *log.Context {
		return logContext
	}

	// Initialize Telemetry
	enableTelemetry := env.LookupBoolValue(logContext, pkg2.EnableTelemetryEnv, true)
	if enableTelemetry {
		startUpTag := fmt.Sprintf("%s:%s", pkg2.StartUpKey, startupParameter.StartUp)
		_ = errorHandling.HandleError(
			logContextFunc,
			telemetry.InitRegistryFromFile(
				logContext,
				startupParameter.TelemetryConfigPath,
				&startUpTag,
			),
		)
	}

	opensearchAddresses := strings.Split(
		os.Getenv(databaseConstants.OpenSearchServer),
		",",
	)

	if startupParameter.EnableConsumer {
		// Wait for containers.
		helpers.WaitForIt(logContext, startupParameter.RootDir, opensearchAddresses[0])
		helpers.WaitForIt(logContext, startupParameter.RootDir, startupParameter.KafkaBrokers[0])
	}

	indexPropertyKeyMap, indexKeyToIndexDefinitionMap, indexKeyToIndexAliasMap, indexAliasOrIndexNameToIndexKeyMap := repository.ReadIndexPropertiesFromDefinitions(
		logContext,
		path.Join(startupParameter.ScriptRootDir, "indices"),
		startupParameter.IndexConfigFilePath,
	)

	indexDependencies, err := dependencies.LoadIndexDependencies(
		startupParameter.IndexDependenciesPath,
	)

	errorHandling.HandleFatal(
		logContext,
		errors.Wrap(err, functionName),
	)

	var indexKeyToIndexNameMap map[string]string
	consulClient := consul.NewConsulClient(logContext)
	synchClient := synchClients.NewSynchronizationClient(
		consulClient,
		pkg.DatabaseVersionConsulKey,
		pkg.LegacyDatabasePauseConsulKey,
	)
	bypassDbVersionCheck := env.LookupBoolValue(logContext, databaseConstants.OpenSearchBypassVersionCheck, false)

	if !bypassDbVersionCheck {
		helpers.WaitForIt(logContext, startupParameter.RootDir, consulClient.Address())
		synchClient.WaitForPublish(logContext)
	}

	tmpSchemaMapper := schemaMapping.NewSchemaMapper(
		logContext,
		startupParameter.MappingConfigPath,
		indexPropertyKeyMap,
		indexDependencies,
		indexKeyToIndexAliasMap,
		indexAliasOrIndexNameToIndexKeyMap,
		nil,
	)

	opensearchMgmtClient := opensearchShared.NewOpenSearchMgmtClient(
		logContext,
		nil,
		indexKeyToIndexDefinitionMap,
		synchClient,
		tmpSchemaMapper,
	)

	indexAliasOrIndexNameToIndexKeyMap, indexKeyToIndexAliasMap, indexKeyToIndexNameMap, err = opensearchMgmtClient.GetIndexAndAliasMaps(
		logContext,
	)

	errorHandling.HandleFatal(
		logContext,
		errors.Wrap(err, functionName),
	)

	applicationInfo.PublishFinished = true

	schemaMapper := telemetry.MeasureWithResult(
		logContext,
		group.Config,
		metric.LoadSchemaMapping,
		func() schemaMapping.SchemaMapper {
			return schemaMapping.NewSchemaMapper(
				logContext,
				startupParameter.MappingConfigPath,
				indexPropertyKeyMap,
				indexDependencies,
				indexKeyToIndexAliasMap,
				indexAliasOrIndexNameToIndexKeyMap,
				indexKeyToIndexNameMap,
			)
		},
	)

	opensearchClient, err := opensearchShared.NewOpenSearchClient(
		logContext,
		opensearchAddresses,
		nil,
		startupParameter.Refresh,
		indexKeyToIndexAliasMap,
		startupParameter.UpdateByQueryScrollSize,
		startupParameter.UpdateByQuerySlices,
	)
	errorHandling.HandleFatal(
		logContext,
		errors.Wrap(err, functionName),
	)

	ctx := context.WithValue(context.Background(), log.LogContextKey, logContext)
	ctx, cancelFunc := context.WithCancel(ctx)

	saramaConsumer, err := kafka.NewSaramaConsumer(
		logContext,
		startupParameter.KafkaBrokers,
		startupParameter.KafkaConsumerTopics,
		startupParameter.KafkaVersion,
		startupParameter.ClientId,
		startupParameter.BatchSize,
		startupParameter.KafkaConnectionMaxRetry,
		ctx,
	)
	errorHandling.HandleFatal(
		logContext,
		errors.Wrap(err, functionName),
	)

	var messageFilter filter.MessageFilter
	if startupParameter.MessageFilterCtor != nil {
		messageFilter = startupParameter.MessageFilterCtor(schemaMapper)
	}

	var (
		messageEmitter = emitter.NewOpenSearchEmitter(
			opensearchClient,
			schemaMapper,
			startupParameter.AuditLogBatchSize,
		)
		mpDependencies = &processor.MessageProcessorDependencies{
			Consumer:     saramaConsumer,
			SchemaMapper: schemaMapper,
			Filter:       messageFilter,
			TransformerCtor: func(mapper schemaMapping.SchemaMapper) transform.Transformer {
				return transform.NewUemPublicEventTransformer(mapper, startupParameter.IgnoreDriftDetection)
			},
			QueryGenerator: queryGenerator.NewQueryGenerator(
				schemaMapper,
				!startupParameter.ProcessOnlyFanOut,
				len(startupParameter.FanOutKafkaTopics) == 0,
				len(startupParameter.FanOutKafkaTopics) > 0,
			),
			Grouper:                   group2.NewGrouper(schemaMapper, startupParameter.AuditLogBatchSize),
			Enricher:                  enrich.NewEnricher(schemaMapper, opensearchClient),
			Emitter:                   messageEmitter,
			RemediationRequestEmitter: startupParameter.RemediationRequestEmitter,
		}
		messageProcessor = startupParameter.MessageProcessorCtor(
			logContext,
			mpDependencies,
			startupParameter.AuditLogBatchSize,
		)
	)

	var (
		saramaProducer streaming.Producer[*streaming.EventReturn]
		dlqProducer    streaming.Producer[*streaming.EventDiscard]
		fanOutProducer streaming.Producer[*streaming.EventReturn]
	)

	if startupParameter.EnableConsumer {
		batchPartitioner := startupParameter.BatchPartitioner(messageProcessor)
		batchQueue := queue.NewAutoFlushQueue(
			logContext,
			startupParameter.BatchSize,
			startupParameter.BatchDocsThreshold,
			batchPartitioner.Partition,
			startupParameter.QueueTimeout,
			func(r interface{}) {
				log.Fatalw(logContext, "Fatal exception occurred.", r)
			},
			newQueueTelemetryProvider(logContext),
		)
		messageProcessor.SetQueue(batchQueue)
		saramaConsumer.SetConsumerLifecycleCallbacks(
			consumerGroupInfo.OnConsumerStarting,
			consumerGroupInfo.OnConsumerFinishing,
			consumerGroupInfo.OnStartConsumingKafkaPartition,
			func(logContext *log.Context, topic string, partition int32) {
				// We need to flush the batch queue after a partition is no longer consumed to make
				// sure all the partition offsets are committed before the rebalance can continue.
				batchQueue.Flush()

				// Update the partition information...
				consumerGroupInfo.OnFinishConsumingKafkaPartition(logContext, topic, partition)
			},
		)
		err = saramaConsumer.BeginConsuming(
			logContext,
			ctx,
			messageProcessor.NewMessageCallback,
		)
		_ = errorHandling.HandleError(logContextFunc, err)

		// Sarama consumer will retry connections to the remote stream.
		// Producers are created after the consumer to ensure no panic.
		setupProducers(
			logContext,
			startupParameter,
			messageProcessor,
			&dlqProducer,
			&fanOutProducer,
			&saramaProducer,
			startupParameter.KafkaProducerTopics,
		)

		registries := []goMetrics.Registry{
			saramaConsumer.GetMetricsRegistry(),
			saramaProducer.GetMetricsRegistry(),
			dlqProducer.GetMetricsRegistry(),
		}

		if fanOutProducer != nil {
			registries = append(registries, fanOutProducer.GetMetricsRegistry())
		}

		// subscribe to sarama metrics
		_, _ = telemetry.SubscribeToMetricRegistries(
			logContext,
			saramaMetricPrefix,
			registries...,
		)
	} else {
		// If we are not consumer (Tier 0), a producer panic is valid.
		setupProducers(
			logContext,
			startupParameter,
			messageProcessor,
			&dlqProducer,
			&fanOutProducer,
			&saramaProducer,
			startupParameter.KafkaProducerTopics,
		)
	}

	// All parameters are set.
	// Create ingestStartup for the caller.
	stUp := &ingestStartup{
		opensearchClient:  opensearchClient,
		doneChannel:       saramaConsumer.Done(),
		ctx:               ctx,
		cancelFunc:        cancelFunc,
		dlqProducer:       dlqProducer,
		schemaMapper:      schemaMapper,
		messageProcessor:  messageProcessor,
		openSearchEmitter: messageEmitter,
	}

	return stUp
}

func setupProducers(
	logContext *log.Context,
	startupParameter *Parameter,
	messageProcessor processor.Processor,
	dlqProducer *streaming.Producer[*streaming.EventDiscard],
	fanOutProducer *streaming.Producer[*streaming.EventReturn],
	saramaProducer *streaming.Producer[*streaming.EventReturn],
	producerKafkaTopics map[string][]string,
) {
	const functionName = "startup.setupProducers"

	var err error

	// DLQ Producer
	*dlqProducer, err = kafka.NewSaramaProducer[*streaming.EventDiscard](
		startupParameter.KafkaConnectionMaxRetry,
		startupParameter.KafkaBrokers,
		map[string][]string{
			constants.DefaultSchema: startupParameter.DLQKafkaTopics,
		},
		startupParameter.DLQClientId,
	)
	errorHandling.HandleFatal(logContext, errors.Wrap(err, functionName))

	// Sarama consumer will wait for kafka to be healthy.
	*saramaProducer, err = kafka.NewSaramaProducer[*streaming.EventReturn](
		startupParameter.KafkaConnectionMaxRetry,
		startupParameter.KafkaBrokers,
		producerKafkaTopics,
		startupParameter.ClientId,
	)
	errorHandling.HandleFatal(logContext, errors.Wrap(err, functionName))

	messageProcessor.SetDLQProducer(*dlqProducer)
	messageProcessor.SetProducer(*saramaProducer)

	if len(startupParameter.FanOutKafkaTopics) > 0 {
		// Fan Out Producer
		*fanOutProducer, err = kafka.NewSaramaProducer[*streaming.EventReturn](
			startupParameter.KafkaConnectionMaxRetry,
			startupParameter.KafkaBrokers,
			map[string][]string{
				constants.DefaultSchema: startupParameter.FanOutKafkaTopics,
			},
			startupParameter.FanOutClientId,
		)
		errorHandling.HandleFatal(logContext, errors.Wrap(err, functionName))
		messageProcessor.SetFanOutProducer(*fanOutProducer)
	}
}

// Done returns done channel for consumer.
func (startup *ingestStartup) Done() <-chan struct{} {
	return startup.doneChannel
}

// Close cancels the consumer context.
func (startup *ingestStartup) Close() {
	startup.cancelFunc()
}

// ReadProvider returns repository.NoSqlReadRepository for querying data.
func (startup *ingestStartup) ReadProvider() repository.NoSqlReadRepository {
	return startup.opensearchClient
}

// Producer returns current instance of the streaming.Producer interface.
func (startup *ingestStartup) Producer() streaming.Producer[*streaming.EventReturn] {
	return startup.messageProcessor.Producer()
}

// DLQProducer returns current instance of the streaming.Producer interface.
func (startup *ingestStartup) DLQProducer() streaming.Producer[*streaming.EventDiscard] {
	return startup.messageProcessor.DLQProducer()
}

// SchemaMapper returns the current schema mapper interface.
func (startup *ingestStartup) SchemaMapper() schemaMapping.SchemaMapper {
	return startup.schemaMapper
}

// MessageProcessor returns the current message processor.Processor interface.
func (startup *ingestStartup) MessageProcessor() processor.Processor {
	return startup.messageProcessor
}

func (startup *ingestStartup) Emitter() emitter.Emitter {
	return startup.openSearchEmitter
}

type queueTelemetryProvider struct {
	logContext *log.Context
}

func newQueueTelemetryProvider(logContext *log.Context) *queueTelemetryProvider {
	return &queueTelemetryProvider{
		logContext: logContext,
	}
}

func (tp *queueTelemetryProvider) CountFlush(reason queue.FlushReason) {
	const flushReasonTagName = "batch-processing-reason"
	telemetry.Increment(
		tp.logContext,
		group.MessageProcessor,
		metric.BatchProcessedCount,
		metrics.NewTag(
			flushReasonTagName,
			reason.String(),
		),
	)
}
