	ingestApp              = "ingest"
	ingestAppApiBasePath   = "/gumdrop-ingestion"
	recoveryApp            = "recovery"
	recoveryAppApiBasePath = "/gumdrop-ingestion-recovery"
	fanOutApp              = "fan-out"
	fanOutAppApiBasePath   = "/gumdrop-ingestion-fan-out"
