			envValueSeparator,
		)
		queueFlushTimeout = env.GetIntValue(
			logContext,
			queue.FlushTimeoutInMilliSeconds,
		)
		batchPartitionCount = env.GetIntValue(logContext, constants.BatchPartitionCount)
		batchSize           = env.GetIntValue(logContext, constants.KafkaBatchSize)
		batchDocsThreshold  = env.GetIntValue(logContext, processor.BatchDocsThreshold)
		maxRetry            = env.GetIntValue(
			logContext,
			constants.KafkaConnectionMaxRetry,
		)
		refresh                          = env.GetBoolValue(logContext, "REFRESH")
		httpRequestTimeout time.Duration = time.Duration(
			env.LookupIntValue(
				logContext,
				pkg.HttpClientRequestTimeoutSecondsEnv,
				30,
			),
		) * time.Second
		transientErrorRetryClientMaxAttempts int = env.LookupIntValue(
			logContext,
			pkg.TransientErrorRetryMaxAttemptsEnv,
			5,
		)
		transientErrorRetryClientBaseDelay time.Duration = time.Duration(
			env.LookupIntValue(
				logContext,
				pkg.TransientErrorRetryBaseDelayMillisecondsEnv,
