	switch startUpApp {
	case ingestApp:
		apiBasePath = ingestAppApiBasePath
		messageFilterCtor = filter.NewMessageFilter
		messageProcessorCtor = processor.NewMessageProcessor
	case fanOutApp:
		apiBasePath = fanOutAppApiBasePath
